// Committed type contract for the generated `surfaceWasmBytes.ts` (the base64
// wasm module, baked by `build:wasm`). This `.d.ts` is always present, so the
// package type-checks with no Rust toolchain; the value is provided at runtime
// by the generated implementation. Stable — the shape never changes.
export declare const surfaceWasmBytes: Uint8Array;
